}

.public-note-layout {
  gap: var(--space-4);
}

.dashboard-hero {
  gap: var(--space-3);
  overflow: hidden;
  padding: 0.9rem 1rem;
}

.dashboard-hero-head {
  gap: 0.75rem;
}

.dashboard-hero-copy {
  gap: var(--space-2);
}

.dashboard-hero .dashboard-hero-title {
  font-size: clamp(1.55rem, 2.8vw, 2.15rem);
  line-height: 0.98;
  letter-spacing: -0.035em;
  margin: 0;
  max-width: 14ch;
}

.dashboard-hero-lede {
  font-size: var(--text-sm);
  line-height: 1.55;
  max-width: 35rem;
}

.dashboard-hero-actions {

}

.ui-surface-hero,
.hero-card {
  box-shadow: var(--shadow-hero);
}

.ui-surface-panel,
.ui-surface-card,
.ui-surface-shell,
.panel-card,
.feature-card,
.vault-frame {
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.58), transparent 22%),
    var(--surface-strong);
}

.ui-surface-inset,
.public-note-metadata {
  background: var(--surface-muted);
  border-radius: var(--radius-3);
  gap: var(--space-4);
  margin-top: var(--space-6);
  padding: var(--space-4);
}

.ui-surface-inset::before,
.public-note-metadata::before {
  display: none;
}

.ui-detail-block,
.detail-block,
.note-list-item,
.link-list-item,
.route-tile,
.tag-filter-link {
  background: rgba(248, 250, 252, 0.92);
  border: 1px solid rgba(148, 163, 184, 0.22);
  border-radius: var(--radius-3);

.public-note-metadata::before {
  background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.9), transparent);
  content: "";
  height: 1px;
  left: var(--space-6);
  position: absolute;
  right: var(--space-6);
  top: 0;
}

.ui-surface,
.hero-card,
.panel-card,
.feature-card,
.vault-frame {
  padding: var(--space-5);
}

.ui-surface-compact {
  padding: 1rem 1.05rem 1.1rem;
}

.ui-surface-hero,
.hero-card {
  box-shadow: var(--shadow-hero);
}

